# 1871. Jump Game VII
from time import time


class Solution:
    def canReach(self, s: str, minJump: int, maxJump: int) -> bool:
        # Edge case
        if s[0] == '1' or s[-1] == '1':
            return False
        
        n = len(s)

        reachable = [False] * n
        reachable[0] = True

        # number of reachable indices inside current valid window
        count = 0

        for i in range(1, n):

            # index entering the window
            left_add = i - minJump
            if left_add >= 0 and reachable[left_add]:
                count += 1

            # index leaving the window
            left_remove = i - maxJump - 1
            if left_remove >= 0 and reachable[left_remove]:
                count -= 1

            # current index reachable?
            if s[i] == '0' and count > 0:
                reachable[i] = True

        return reachable[-1]




inputs =[
    ("011010", 2, 3, True),
    ("01101110", 2, 3, False),
    ("0"*100000, 5, 99998, True),
    ("0"*99999+"1", 1, 99999, False),
    (
        "",
        1,
        49999,
        False
    ),
    (
        "",
        1,
        49999,
        False
    ),
    (
        "",
        1,
        49999,
        False
    ),
    (
        "",
        3,
        7,
        None
    )

]
solution = Solution()
for s, minJump, maxjump, result in inputs:
    my_result = solution.canReach(s, minJump, maxjump)
    print(my_result, my_result==result)

